     4	export interface RoomState {
     5	  session_status: string
     6	  enrolled_count: number
     7	  checked_in_count: number
     8	}
     9	
    10	export interface RoomEvent {
    11	  type: string
    12	  payload: Record<string, unknown>
    13	  timestamp: Date
    14	}
    15	
    16	export function useWebSocket(sessionId: string) {
    17	  const auth = useAuthStore()
    18	  const roomState = ref<RoomState | null>(null)
    19	  const events = ref<RoomEvent[]>([])
    20	  const connectionStatus = ref<'connecting' | 'connected' | 'disconnected' | 'error'>('connecting')
    21	
    22	  const wsRef = ref<WebSocket | null>(null)
    23	  let ws: WebSocket | null = null
    24	  let retryDelay = 1000
    25	  let retryTimeout: ReturnType<typeof setTimeout> | null = null
    26	  let destroyed = false
    27	
    28	  function connect() {
    29	    if (destroyed) return
    30	    const token = auth.accessToken
    31	    if (!token) { connectionStatus.value = 'error'; return }
    32	
    33	    const protocol = window.location.protocol === 'https:' ? 'wss:' : 'ws:'
    34	    const url = `${protocol}//${window.location.host}/api/ws/sessions/${sessionId}/room?token=${token}`
    35	
    36	    ws = new WebSocket(url)
    37	    wsRef.value = ws
    38	    connectionStatus.value = 'connecting'
    39	
    40	    ws.onopen = () => {
    41	      connectionStatus.value = 'connected'
    42	      retryDelay = 1000
    43	    }
    44	
    45	    ws.onmessage = (evt) => {
    46	      let msg: Record<string, unknown>
    47	      try { msg = JSON.parse(evt.data) } catch { return }
    48	
    49	      const type = msg.type as string
    50	      const next = [{ type, payload: msg, timestamp: new Date() }, ...events.value]
    51	      events.value = next.length > 100 ? next.slice(0, 100) : next
    52	
    53	      if (type === 'room_state') {
    54	        roomState.value = {
    55	          session_status: msg.session_status as string,
    56	          enrolled_count: msg.enrolled_count as number,
    57	          checked_in_count: msg.checked_in_count as number,
    58	        }
    59	      } else if (type === 'session_status_changed') {
    60	        if (roomState.value) roomState.value.session_status = msg.status as string
    61	      } else if (type === 'attendee_joined') {
    62	        if (roomState.value) roomState.value.checked_in_count++
    63	      } else if (type === 'attendee_left') {
    64	        if (roomState.value && roomState.value.checked_in_count > 0) roomState.value.checked_in_count--
    65	      } else if (type === 'roster_update') {
    66	        if (roomState.value) roomState.value.enrolled_count = msg.enrolled_count as number
    67	      }
    68	    }
    69	
    70	    ws.onerror = () => { connectionStatus.value = 'error' }
    71	
    72	    ws.onclose = (evt) => {
    73	      connectionStatus.value = 'disconnected'
    74	      if (!destroyed && evt.code !== 1000) {
    75	        // Exponential backoff, max 30s
    76	        retryTimeout = setTimeout(() => { retryDelay = Math.min(retryDelay * 2, 30000); connect() }, retryDelay)
    77	      }
    78	    }
    79	  }
